2611       return Neg;
2612     }
2613 
2614     Known = KnownFPClass::fmul(KnownLHS, KnownRHS, Mode);
2615     Known.knownNot(~DemandedMask);
2616 
2617     if (Constant *SingleVal = getFPClassConstant(VTy, Known.KnownFPClasses,
2618                                                  /*IsCanonicalizing=*/true))
2619       return SingleVal;
2620 
2621     FastMathFlags InferredFMF = inferFastMathValueFlags(
2622         FMF, Known.KnownFPClasses, {KnownLHS, KnownRHS});
2623     if (InferredFMF != FMF) {
2624       I->setFastMathFlags(InferredFMF);
2625       return I;
2626     }
2627 
2628     return nullptr;
2629   }
2630   case Instruction::FDiv: {
2631     Value *X = I->getOperand(0);
2632     Value *Y = I->getOperand(1);
2633     if (X == Y && isGuaranteedNotToBeUndef(X, SQ.AC, CxtI, SQ.DT, Depth + 1)) {
2634       // If the source is 0, inf or nan, the result is a nan
2635       IRBuilderBase::InsertPointGuard Guard(Builder);
2636       Builder.SetInsertPoint(I);
2637 
2638       Value *IsZeroOrNan = Builder.CreateFCmpFMF(
2639           FCmpInst::FCMP_UEQ, I->getOperand(0), ConstantFP::getZero(VTy), FMF);
2640 
2641       Value *Fabs =
2642           Builder.CreateUnaryIntrinsic(Intrinsic::fabs, I->getOperand(0), FMF);
2643       Value *IsInfOrNan = Builder.CreateFCmpFMF(
2644           FCmpInst::FCMP_UEQ, Fabs, ConstantFP::getInfinity(VTy), FMF);
2645 
2646       Value *IsInfOrZeroOrNan = Builder.CreateOr(IsInfOrNan, IsZeroOrNan);
2647 
2648       return Builder.CreateSelectFMFWithUnknownProfile(
2649           IsInfOrZeroOrNan, ConstantFP::getQNaN(VTy),
2650           ConstantFP::get(
2651               VTy, APFloat::getOne(VTy->getScalarType()->getFltSemantics())),
2652           FMF, DEBUG_TYPE);
2653     }
2654 
2655     Type *EltTy = VTy->getScalarType();
2656     DenormalMode Mode = F.getDenormalMode(EltTy->getFltSemantics());
2657 
2658     // Every output class could require denormal inputs (except for the
2659     // degenerate case of only-nan results, without DAZ).
2660     FPClassTest SrcDemandedMask = (DemandedMask & fcNan) | fcSubnormal;
2661 
2662     // Normal inputs may result in underflow.
2663     // x / x = 1.0 for non0/inf/nan
2664     // -x = +y / -z
2665     // -x = -y / +z
2666     if (DemandedMask & (fcSubnormal | fcNormal))
2667       SrcDemandedMask |= fcNormal;
2668 
2669     if (DemandedMask & fcNan) {
2670       // 0 / 0 = nan
2671       // inf / inf = nan
2672 
2673       // Subnormal is added in case of DAZ, but this isn't strictly
2674       // necessary. Every other input class implies a possible subnormal source,
2675       // so this only could matter in the degenerate case of only-nan results.
2676       SrcDemandedMask |= fcZero | fcInf | fcNan;
2677     }
2678 
2679     // Zero outputs may be the result of underflow.
2680     if (DemandedMask & fcZero)
2681       SrcDemandedMask |= fcNormal | fcSubnormal;
2682 
2683     FPClassTest LHSDemandedMask = SrcDemandedMask;
2684     FPClassTest RHSDemandedMask = SrcDemandedMask;
2685 
2686     // 0 / inf = 0
2687     if (DemandedMask & fcZero) {
2688       assert((LHSDemandedMask & fcSubnormal) &&
2689              "should not have to worry about daz here");
2690       LHSDemandedMask |= fcZero;
2691       RHSDemandedMask |= fcInf;
2692     }
2693 
2694     // x / 0 = inf
2695     // large_normal / small_normal = inf
2696     // inf / 1 = inf
2697     // large_normal / subnormal = inf
2698     if (DemandedMask & fcInf) {
2699       LHSDemandedMask |= fcInf | fcNormal | fcSubnormal;
2700       RHSDemandedMask |= fcZero | fcSubnormal | fcNormal;
2701     }
2702 
2703     KnownFPClass KnownLHS, KnownRHS;
2704     if (SimplifyDemandedFPClass(I, 0, LHSDemandedMask, KnownLHS, Depth + 1) ||
2705         SimplifyDemandedFPClass(I, 1, RHSDemandedMask, KnownRHS, Depth + 1))
2706       return I;
2707 
2708     // nsz [+-]0 / x -> 0
2709     if (FMF.noSignedZeros() && KnownLHS.isKnownAlways(fcZero) &&
2710         KnownRHS.isKnownNeverNaN())
2711       return ConstantFP::getZero(VTy);
2712 
2713     if (KnownLHS.isKnownAlways(fcPosZero) && KnownRHS.isKnownNeverNaN()) {
2714       IRBuilderBase::InsertPointGuard Guard(Builder);
2715       Builder.SetInsertPoint(I);
2716 
2717       // nnan +0 / x -> copysign(0, rhs)
2718       // TODO: -0 / x => copysign(0, fneg(rhs))
2719       Value *Copysign = Builder.CreateCopySign(X, Y, FMF);
2720       Copysign->takeName(I);
2721       return Copysign;
2722     }
2723 
2724     bool ResultNotNan = (DemandedMask & fcNan) == fcNone;
2725     bool ResultNotInf = (DemandedMask & fcInf) == fcNone;
2726 
2727     if (!ResultNotInf &&
2728         ((ResultNotNan || (KnownLHS.isKnownNeverNaN() &&
2729                            KnownLHS.isKnownNeverLogicalZero(Mode))) &&
2730          (KnownRHS.isKnownAlways(fcPosZero) ||
2731           (FMF.noSignedZeros() && KnownRHS.isKnownAlways(fcZero))))) {
2732       IRBuilderBase::InsertPointGuard Guard(Builder);
2733       Builder.SetInsertPoint(I);
2734 
2735       // nnan x / 0 => copysign(inf, x);
2736       // nnan nsz x / -0 => copysign(inf, x);
2737       Value *Copysign =
2738           Builder.CreateCopySign(ConstantFP::getInfinity(VTy), X, FMF);
2739       Copysign->takeName(I);
2740       return Copysign;
2741     }
2742 
2743     // nnan ninf X / [-]0.0 -> poison
2744     if (ResultNotNan && ResultNotInf && KnownRHS.isKnownAlways(fcZero))
2745       return PoisonValue::get(VTy);
2746 
2747     Known = KnownFPClass::fdiv(KnownLHS, KnownRHS, Mode);
2748     Known.knownNot(~DemandedMask);
2749 
2750     if (Constant *SingleVal = getFPClassConstant(VTy, Known.KnownFPClasses,
2751                                                  /*IsCanonicalizing=*/true))
2752       return SingleVal;
2753 
2754     FastMathFlags InferredFMF = inferFastMathValueFlags(
2755         FMF, Known.KnownFPClasses, {KnownLHS, KnownRHS});
2756     if (InferredFMF != FMF) {
2757       I->setFastMathFlags(InferredFMF);
2758       return I;
2759     }
2760 
2761     return nullptr;
2762   }
2763   case Instruction::FPTrunc:
2764     return simplifyDemandedUseFPClassFPTrunc(*this, *I, FMF, DemandedMask,
2765                                              Known, Depth);
2766   case Instruction::FPExt: {
2767     FPClassTest SrcDemandedMask = DemandedMask;
2768     if (DemandedMask & fcNan)
2769       SrcDemandedMask |= fcNan;
2770 
2771     // No subnormal result does not imply not-subnormal in the source type.
2772     if ((DemandedMask & fcNegNormal) != fcNone)
2773       SrcDemandedMask |= fcNegSubnormal;
2774     if ((DemandedMask & fcPosNormal) != fcNone)
2775       SrcDemandedMask |= fcPosSubnormal;
2776 
2777     KnownFPClass KnownSrc;
2778     if (SimplifyDemandedFPClass(I, 0, SrcDemandedMask, KnownSrc, Depth + 1))
2779       return I;
2780 
2781     const fltSemantics &DstTy = VTy->getScalarType()->getFltSemantics();
2782     const fltSemantics &SrcTy =
2783         I->getOperand(0)->getType()->getScalarType()->getFltSemantics();
2784 
2785     Known = KnownFPClass::fpext(KnownSrc, DstTy, SrcTy);
2786     Known.knownNot(~DemandedMask);
2787 
2788     return simplifyDemandedFPClassResult(I, FMF, DemandedMask, Known,
2789                                          {KnownSrc});
2790   }
2791   case Instruction::Call: {
2792     CallInst *CI = cast<CallInst>(I);
2793     const Intrinsic::ID IID = CI->getIntrinsicID();
2794     switch (IID) {
2795     case Intrinsic::fabs: {
2796       KnownFPClass KnownSrc;
2797       if (SimplifyDemandedFPClass(I, 0, llvm::inverse_fabs(DemandedMask),
2798                                   KnownSrc, Depth + 1))
2799         return I;
2800 
2801       if (Value *Simplified = simplifyDemandedFPClassFabs(
2802               Known, CI->getArgOperand(0), DemandedMask, KnownSrc,
2803               FMF.noSignedZeros()))
2804         return Simplified;
2805       break;
2806     }
2807     case Intrinsic::arithmetic_fence:
2808       if (SimplifyDemandedFPClass(I, 0, DemandedMask, Known, Depth + 1))
2809         return I;
2810       break;
2811     case Intrinsic::copysign: {
2812       // Flip on more potentially demanded classes
2813       const FPClassTest DemandedMaskAnySign = llvm::unknown_sign(DemandedMask);
2814       KnownFPClass KnownMag;
2815       if (SimplifyDemandedFPClass(CI, 0, DemandedMaskAnySign, KnownMag,
2816                                   Depth + 1))
2817         return I;
