3549 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3550                                                FPClassTest DemandedMask,
3551                                                KnownFPClass &Known,
3552                                                unsigned Depth) {
3553   Use &U = I->getOperandUse(OpNo);
3554   Value *V = U.get();
3555   Type *VTy = V->getType();
3556 
3557   if (DemandedMask == fcNone) {
3558     if (isa<PoisonValue>(V))
3559       return false;
3560     replaceUse(U, PoisonValue::get(VTy));
3561     return true;
3562   }
3563 
3564   // Handle constant
3565   Instruction *VInst = dyn_cast<Instruction>(V);
3566   if (!VInst) {
3567     // Handle constants and arguments
3568     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3569     Known.knownNot(~DemandedMask);
3570 
3571     if (Known.KnownFPClasses == fcNone) {
3572       if (isa<PoisonValue>(V))
3573         return false;
3574       replaceUse(U, PoisonValue::get(VTy));
3575       return true;
3576     }
3577 
3578     // Do not try to replace values which are already constants (unless we are
3579     // folding to poison). Doing so could promote poison elements to non-poison
3580     // constants.
3581     if (isa<Constant>(V))
3582       return false;
3583 
3584     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3585     if (!FoldedToConst || FoldedToConst == V)
3586       return false;
3587 
3588     replaceUse(U, FoldedToConst);
3589     return true;
3590   }
3591 
3592   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3593     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3594     DemandedMask &= ~NoFPClass;
3595   }
3596 
3597   if (Depth == MaxAnalysisRecursionDepth) {
3598     Known.knownNot(~DemandedMask);
3599     return false;
3600   }
3601 
3602   Value *NewVal;
3603 
3604   if (VInst->hasOneUse()) {
3605     // If the instruction has one use, we can directly simplify it.
3606     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3607   } else {
3608     // If there are multiple uses of this instruction, then we can simplify
3609     // VInst to some other value, but not modify the instruction.
3610     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3611                                                 Depth);
3612   }
3613 
3614   if (!NewVal)
3615     return false;
3616   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3617     salvageDebugInfo(*OpInst);
3618 
3619   replaceUse(U, NewVal);
3620   return true;
3621 }
